import{o as t,c as r,j as s,n as i,e as n,ae as l,p as c}from"./chunks/framework.BSk3HXt1.js";const o={class:"language-toggle-wrapper"},h={class:"language-toggle-bar"},p={class:"bilingual-title"},g={key:0,class:"zh-text"},b={key:1,class:"en-text"},w=JSON.parse('{"title":"美利堅甜蜜拼圖：15款不可錯過的在地標誌性甜點 | American desserts: 15 sweet regional treats to try","description":"","frontmatter":{"outline":[2,3],"title":"美利堅甜蜜拼圖：15款不可錯過的在地標誌性甜點 | American desserts: 15 sweet regional treats to try"},"headers":[],"relativePath":"news/best-american-regional-desserts.md","filePath":"news/best-american-regional-desserts.md"}'),x={name:"news/best-american-regional-desserts.md"},y=Object.assign(x,{setup(v){const e=c("bilingual");return(m,a)=>(t(),r("div",null,[s("div",o,[s("div",h,[s("button",{class:i(["language-toggle-btn",{active:e.value==="bilingual"}]),onClick:a[0]||(a[0]=d=>e.value="bilingual")},"中英雙語",2),s("button",{class:i(["language-toggle-btn",{active:e.value==="zh"}]),onClick:a[1]||(a[1]=d=>e.value="zh")},"純中文",2),s("button",{class:i(["language-toggle-btn",{active:e.value==="en"}]),onClick:a[2]||(a[2]=d=>e.value="en")},"純英文",2)])]),s("div",{class:i("bilingual-article mode-"+e.value)},[s("h1",p,[e.value!=="en"?(t(),r("span",g,"美利堅甜蜜拼圖：盤點 15 款不容錯過的美國在地標誌性甜點")):n("",!0),e.value!=="zh"?(t(),r("span",b,"American desserts: 15 sweet regional treats to try")):n("",!0)]),a[3]||(a[3]=l('<div style="text-align:center;margin:24px 0 32px 0;"><img src="/ai-news/best-american-regional-desserts/hero.webp" alt="Classic American Desserts" style="border-radius:16px;max-width:100%;box-shadow:0 8px 32px rgba(0,0,0,0.15);border:1px solid rgba(255,255,255,0.08);"></div><div class="bilingual-paragraph"><p class="zh-text">從俄亥俄州的「七葉樹巧克力」、新墨西哥州的「茴香肉桂脆餅」，到奧勒岡州的「馬里恩莓派」——在幅員遼闊的美國各個角落，當地居民都精心配製出了獨特的甜蜜佳餚，絕對值得來訪的旅人們一探究竟。其中有些美味甚至因為太受歡迎，引發了各州對其正統起源的激烈爭奪戰。以下精選了 15 款橫跨全美、最具代表性的地區性甜點。</p><p class="en-text">Buckeyes, biscochitos, marionberry pie. All over the United States, locals have concocted sweet treats that visitors should definitely sample. Some are so delicious they’re worth fighting over. Here are 15 of the best regional desserts to tuck into across America.</p></div><hr><h2 class="bilingual-header"><span class="zh-text">🍰 全美傳奇甜點圖錄</span><span class="en-text">The Best American Regional Desserts</span></h2><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">1. 烏比派 (Whoopie pie)</h3><span class="dish-card-badge">New England &amp; Pennsylvania</span></div><div style="text-align:center;margin:16px 0;"><img src="/ai-news/best-american-regional-desserts/dessert_1_whoopie_pie.webp" alt="Whoopie pie" style="border-radius:12px;max-width:100%;max-height:400px;box-shadow:0 4px 20px rgba(0,0,0,0.12);"></div><div class="bilingual-paragraph"><p class="zh-text">美食起源的故事向來備受爭議，烏比派也不例外。賓州與緬因州都聲稱自己才是這款夾有滑順奶油餡、宛如蛋糕質地的巧克力餅乾三明治的發源地。賓州表示這是阿米希廚師的心血結晶；而緬因州則宣稱其 1920 年代就在路易斯頓的麵包店開始販售，甚至在 2011 年將其正式定為官方的「州款待點心」。</p><p class="en-text">The origin stories of delicious creations are often contested, and the whoopie pie is no exception. Pennsylvania and Maine claim to be the birthplace of these chocolate cake-like cookie sandwiches filled with cream. Maine made it the official state &quot;treat&quot; in 2011.</p></div></div><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">2. 雷恩蛋糕 (Lane cake)</h3><span class="dish-card-badge">Alabama</span></div><div style="text-align:center;margin:16px 0;"><img src="/ai-news/best-american-regional-desserts/dessert_2_lane_cake.webp" alt="Lane cake" style="border-radius:12px;max-width:100%;max-height:400px;box-shadow:0 4px 20px rgba(0,0,0,0.12);"></div><div class="bilingual-paragraph"><p class="zh-text">阿拉巴馬州也有欽定的官方「州蛋糕」：雷恩蛋糕。這款千層蛋糕的靈魂精髓在於其夾餡——以奶油、波本威士忌或白蘭地浸泡過的葡萄乾混合物，有時還會奢華地加入山核桃與椰子。它的創始者艾瑪·雷恩甚至將食譜記錄在 1898 年的食譜書中，這款南方甜點甚至還出現在文學經典《梅岡城故事》的書頁中。</p><p class="en-text">Alabama’s got a state dessert, too: Lane cake. The star of this layer cake is the filling – a buttery, bourbon- or brandy-spiked raisin mixture sometimes with pecans. The Southern sweet also makes it into the pages of Harper Lee’s “To Kill a Mockingbird.”</p></div></div><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">3. 馬里恩莓派 (Marionberry pie)</h3><span class="dish-card-badge">Oregon</span></div><div style="text-align:center;margin:16px 0;"><img src="/ai-news/best-american-regional-desserts/dessert_3_marionberry_pie.webp" alt="Marionberry pie" style="border-radius:12px;max-width:100%;max-height:400px;box-shadow:0 4px 20px rgba(0,0,0,0.12);"></div><div class="bilingual-paragraph"><p class="zh-text">這種以奧勒岡州馬里恩縣命名的莓果，據稱擁有一種「微酸、飽滿且帶泥土芬芳的甘甜」。將它們烘焙成派後極具風味，每逢七月，當地麵包店就會湧現將莓果封存於濃郁香酥奶油派皮中的美味浪潮。波特蘭的知名派店更是會把握這短暫而甜美的產季推出經典口味。</p><p class="en-text">Named for Marion County, the marionberry has “a tart, earthy sweetness.” They’re also very good in pies, and come July, bakeries are brimming with berries baked into rich, buttery crusts.</p></div></div><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">4. 萊姆派 (Key lime pie)</h3><span class="dish-card-badge">Florida</span></div><div style="text-align:center;margin:16px 0;"><img src="/ai-news/best-american-regional-desserts/dessert_4_key_lime_pie.webp" alt="Key lime pie" style="border-radius:12px;max-width:100%;max-height:400px;box-shadow:0 4px 20px rgba(0,0,0,0.12);"></div><div class="bilingual-paragraph"><p class="zh-text">這款具備代表性的經典萊姆派，毫無疑問與「陽光之州」有著極深的淵源，它是基韋斯特（Key West）的招牌佳餚。標準做法是在葛拉漢餅乾派底中，注入由大量鮮榨萊姆汁與香甜煉乳調製成的酸爽卡士達醬，完美融合酸與甜的味覺平衡。</p><p class="en-text">The pie undoubtedly has strong ties to the Sunshine State and is Key West’s signature dish. Typically, a graham cracker crust is filled with a tart custard made with plenty of juice and sweetened condensed milk.</p></div></div><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">5. 黏糯奶油蛋糕 (Gooey butter cake)</h3><span class="dish-card-badge">Missouri</span></div><div style="text-align:center;margin:16px 0;"><img src="/ai-news/best-american-regional-desserts/dessert_5_gooey_butter_cake.webp" alt="Gooey butter cake" style="border-radius:12px;max-width:100%;max-height:400px;box-shadow:0 4px 20px rgba(0,0,0,0.12);"></div><div class="bilingual-paragraph"><p class="zh-text">聖路易斯（St. Louis）的黏糯奶油蛋糕被認為是 1930 年代一場美麗的食材比例失誤而誕生的傑作。這款質地紮實、扁平，且中心帶著濕潤滑黏口感的蛋糕遍佈聖路易斯街頭，不論是經典原味或是檸檬、山核桃等改良口味，表面撒上一層輕盈的糖粉後都極其誘人。</p><p class="en-text">St. Louis gooey butter cake is thought to be the result of a happy accident in the 1930s. The dense, flat cake with a gooey center is for sale all over St. Louis, often dusted with powdered sugar.</p></div></div><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">6. 夏威夷刨冰 (Shave ice)</h3><span class="dish-card-badge">Hawaii</span></div><div style="text-align:center;margin:16px 0;"><img src="/ai-news/best-american-regional-desserts/dessert_6_shave_ice.webp" alt="Shave ice" style="border-radius:12px;max-width:100%;max-height:400px;box-shadow:0 4px 20px rgba(0,0,0,0.12);"></div><div class="bilingual-paragraph"><p class="zh-text">這款刨冰最初是由來自日本的糖廠勞工引進夏威夷的。輕盈如雪花的冰片從冰磚上刨落，充分吸飽你所挑選的糖漿精華。像是 1951 年就立足歐胡島北岸的老店 Matsumoto，提供的口味甚至橫跨了充滿海島風情的百香果與醃芒果，還有煉乳、香草冰淇淋以及紅豆可供加點。</p><p class="en-text">Shave ice came to Hawaii via sugar plantation workers from Japan. Soft flakes of ice shaved from a solid block soak up the sweet syrup. Established in 1951, Matsumoto Shave Ice has been serving refreshing treats including passion fruit flavors.</p></div></div><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">7. 巧克力核桃派 (Derby-Pie)</h3><span class="dish-card-badge">Kentucky</span></div><div style="text-align:center;margin:16px 0;"><img src="/ai-news/best-american-regional-desserts/dessert_7_chocolate_nut_pie.webp" alt="Derby Pie" style="border-radius:12px;max-width:100%;max-height:400px;box-shadow:0 4px 20px rgba(0,0,0,0.12);"></div><div class="bilingual-paragraph"><p class="zh-text">這款發源於肯塔基州的美味巧克力核桃派曾經引發數次法律攻防戰。路易斯維爾的 Kern’s Kitchen 表示，他們在 1950 年代首創的此款派擁有獨一無二的地位，並為名稱「Derby-Pie®」註冊了嚴格保護的商標，商家甚至不惜多次興訟來守護這塊招牌。</p><p class="en-text">Legal battles have been fought over a delicious chocolate walnut pie from Kentucky. Kern’s Kitchen in Louisville has a registered trademark on the name “Derby-Pie®” and is very serious about protecting it.</p></div></div><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">8. 摩拉維亞糖蛋糕 (Moravian sugar cake)</h3><span class="dish-card-badge">North Carolina &amp; Pennsylvania</span></div><div style="text-align:center;margin:16px 0;"><img src="/ai-news/best-american-regional-desserts/dessert_8_moravian_sugar_cake.webp" alt="Moravian sugar cake" style="border-radius:12px;max-width:100%;max-height:400px;box-shadow:0 4px 20px rgba(0,0,0,0.12);"></div><div class="bilingual-paragraph"><p class="zh-text">這款咖啡蛋糕的歷史可追溯至數百年前，它是摩拉維亞教會定居者留下的飲食傳承，極適合作為假日早午餐或下午茶良伴。北卡羅萊納州的溫斯頓-薩勒姆（Winston-Salem）自 1930 年起便以此聞名，那裡同時也是極薄薄脆糖蜜脆餅的生產重鎮。</p><p class="en-text">This coffee cake has roots in Moravian Church settlements in North Carolina and Pennsylvania dating back hundreds of years. In North Carolina, Winston-Salem has been baking the buttery cakes since 1930.</p></div></div><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">9. 七葉樹巧克力 (Buckeyes)</h3><span class="dish-card-badge">Ohio</span></div><div style="text-align:center;margin:16px 0;"><img src="/ai-news/best-american-regional-desserts/dessert_9_buckeyes.webp" alt="Buckeyes" style="border-radius:12px;max-width:100%;max-height:400px;box-shadow:0 4px 20px rgba(0,0,0,0.12);"></div><div class="bilingual-paragraph"><p class="zh-text">花生醬結合巧克力，而且完全不需要烘烤，怎麼能不愛它？這款糖果得名自俄亥俄州的別稱「七葉樹之州」（Buckeye State），因為成品就像極了該樹木種子酷似鹿眼睛的外觀。製作時會留下一小圈花生醬露在頂端不沾巧克力，簡單又直拳出擊的美味早已傳遍全美。</p><p class="en-text">Peanut butter and chocolate with no baking necessary. This candy hails from the Buckeye State. The bite-sized sweets cover most of the peanut butter ball in a layer of dark chocolate, resembling the eye of a deer.</p></div></div><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">10. 波士頓奶油派 (Boston cream pie)</h3><span class="dish-card-badge">Massachusetts</span></div><div style="text-align:center;margin:16px 0;"><img src="/ai-news/best-american-regional-desserts/dessert_10_boston_cream_pie.webp" alt="Boston cream pie" style="border-radius:12px;max-width:100%;max-height:400px;box-shadow:0 4px 20px rgba(0,0,0,0.12);"></div><div class="bilingual-paragraph"><p class="zh-text">「披著派皮外衣的蛋糕。」《洋基雜誌》曾如此精妙描述它。它由兩層鬆軟金黃的蛋糕體夾住濃郁的甜卡士達醬，頂端再淋上一層滑順鏡面的巧克力甘納許。這款披著羊皮的派發源於 1855 年開幕的帕克豪斯酒店，是麻州指定的官方甜點。</p><p class="en-text">“A pie in cake’s clothing.” It involves sweet pastry cream sandwiched between two rounds of golden cake, finished with a smooth chocolate glaze. Originated at Boston’s Parker House Hotel in 1855.</p></div></div><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">11. 福斯特火焰香蕉 (Bananas Foster)</h3><span class="dish-card-badge">Louisiana</span></div><div style="text-align:center;margin:16px 0;"><img src="/ai-news/best-american-regional-desserts/dessert_11_bananas_foster.webp" alt="Bananas Foster" style="border-radius:12px;max-width:100%;max-height:400px;box-shadow:0 4px 20px rgba(0,0,0,0.12);"></div><div class="bilingual-paragraph"><p class="zh-text">融合了奶油、紅糖、肉桂、蘭姆酒與香蕉酒的極致香濃，並在餐桌旁現場點燃火焰進行「火焰料理（Flambé）」，最後淋在清爽的香草冰淇淋上。這道視覺與味覺饗宴的料理誕生於紐奧良的 Brennan&#39;s 餐廳，至今仍是該店橫掃早午晚三餐的超人氣熱門點單冠軍。</p><p class="en-text">This banana dish involving butter, brown sugar, cinnamon, rum and banana liqueur is set on fire tableside and served over vanilla ice cream. Concocted at Brennan’s Restaurant in New Orleans in 1951.</p></div></div><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">12. 史密斯島蛋糕 (Smith Island cake)</h3><span class="dish-card-badge">Maryland</span></div><div style="text-align:center;margin:16px 0;"><img src="/ai-news/best-american-regional-desserts/dessert_12_smith_island_cake.webp" alt="Smith Island cake" style="border-radius:12px;max-width:100%;max-height:400px;box-shadow:0 4px 20px rgba(0,0,0,0.12);"></div><div class="bilingual-paragraph"><p class="zh-text">這是一款堆疊多達十層薄薄黃色蛋糕體、並以滑順軟糖霜（Fudge）作為夾層間隔的浮誇甜點，發源於切薩皮克灣的一座小島。2008 年被指定為馬里蘭州官方甜點後名聲大噪，如今全美民眾都可以透過產地直郵配送，享受到這精雕細琢的工藝級糕點。</p><p class="en-text">With up to 10 thin layers of yellow cake separated by fudge frosting, this cake originated on Maryland’s Smith Island. It was designated Maryland’s official state dessert in 2008.</p></div></div><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">13. 椰子蛋糕 (Coconut cake)</h3><span class="dish-card-badge">Southern States</span></div><div style="text-align:center;margin:16px 0;"><img src="/ai-news/best-american-regional-desserts/dessert_13_coconut_cake.webp" alt="Coconut cake" style="border-radius:12px;max-width:100%;max-height:400px;box-shadow:0 4px 20px rgba(0,0,0,0.12);"></div><div class="bilingual-paragraph"><p class="zh-text">椰子蛋糕確切的起源已難以考證，但自 19 世紀以來，這款表面鋪滿細雪般椰子刨絲的奢華千層蛋糕，就與美國南方畫上等號。知名糕點作家指出，當時被奴役的非裔廚師掌握了椰子等當時罕見食材的處理精髓，創造出南方史上最頂級精湛的蛋糕奇蹟。</p><p class="en-text">The precise origins are hard to pin down, but decadent layer cakes covered in shaved coconut have been associated with the South since the 1800s.</p></div></div><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">14. 茴香肉桂脆餅 (Biscochitos)</h3><span class="dish-card-badge">New Mexico</span></div><div style="text-align:center;margin:16px 0;"><img src="/ai-news/best-american-regional-desserts/dessert_14_biscochitos.webp" alt="Biscochitos" style="border-radius:12px;max-width:100%;max-height:400px;box-shadow:0 4px 20px rgba(0,0,0,0.12);"></div><div class="bilingual-paragraph"><p class="zh-text">這款帶著茴香獨特香氣、表面撒滿肉桂糖粉的餅乾，最早由早期的西班牙殖民者傳入新墨西哥州。自 1989 年起便被正式定為該州的官方指定餅乾。通常採用豬油揉製麵團並擀成極薄片狀，是當地不可或缺的聖誕節傳統、婚禮與各類盛大慶祝典禮上的幸福點綴。</p><p class="en-text">This anise-flavored cookie topped with cinnamon sugar was brought by early Spanish colonists. The biscochito has been the official state cookie since 1989 and is a Christmas tradition.</p></div></div><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">15. 德州烤盤蛋糕 (Texas sheet cake)</h3><span class="dish-card-badge">Texas</span></div><div style="text-align:center;margin:16px 0;"><img src="/ai-news/best-american-regional-desserts/dessert_15_texas_sheet_cake.webp" alt="Texas sheet cake" style="border-radius:12px;max-width:100%;max-height:400px;box-shadow:0 4px 20px rgba(0,0,0,0.12);"></div><div class="bilingual-paragraph"><p class="zh-text">它如何與這顆孤星州（Lone Star State）扯上關係至今仍是未解之謎，不過其巨大的尺寸可能是主因。這款蛋糕通常在做果凍卷的大型烤盤上烘烤，因此表面積寬廣恢弘。可可粉是蛋糕體與頂層糖霜的核心靈魂主角，糖霜內更奢華混入大量的堅果仁，一口咬下盡是德州式的豪邁風範。</p><p class="en-text">Often baked in a large jelly-roll pan, this thin chocolate cake is expansive. Cocoa is the standout ingredient in both cake and frosting, with nuts mixed into the latter.</p></div></div><div class="original-source-wrapper"><div class="source-label"><span class="zh-text">🌐 閱讀英文原文：</span><span class="en-text">🌐 Read Original Article:</span></div><a href="https://edition.cnn.com/travel/best-american-regional-desserts" target="_blank" rel="noopener noreferrer" class="source-link-btn"> CNN Travel <span style="font-size:0.8rem;">↗</span></a></div>',20))],2)]))}});export{w as __pageData,y as default};
